## 3. Common 라이브러리 상세

### 3.1 PacketType.cs
```csharp
namespace RemoteDesktop.Common.Protocol;

public enum PacketType : byte
{
    AuthRequest    = 0x01,
    AuthResponse   = 0x02,
    AuthChallenge  = 0x03,
    ScreenFull     = 0x10,
    MouseMove      = 0x20,
    MouseClick     = 0x21,
    MouseScroll    = 0x22,
    KeyEvent       = 0x30,
    Heartbeat      = 0xF0
}
```

### 3.2 Packet.cs
```csharp
namespace RemoteDesktop.Common.Protocol;

/// <summary>
/// [4바이트 길이][1바이트 타입][N바이트 페이로드]
/// 길이 = 타입(1) + 페이로드(N)
/// </summary>
public readonly struct Packet
{
    public PacketType Type { get; init; }
    public byte[] Payload { get; init; }

    public int TotalLength => 4 + 1 + (Payload?.Length ?? 0);
}
```

