### 3.5 PacketPayloads.cs
```csharp
namespace RemoteDesktop.Common.Protocol;

// === 인증 ===

/// <summary>AUTH_CHALLENGE: Agent → Client</summary>
public class AuthChallengePayload
{
    public byte[] Nonce { get; set; } // 32바이트 랜덤
    public byte[] Serialize();
    public static AuthChallengePayload Deserialize(byte[] data);
}

/// <summary>AUTH_REQUEST: Client → Agent (챌린지 응답)</summary>
public class AuthRequestPayload
{
    public byte[] HashedResponse { get; set; } // SHA256(nonce + password)
    public byte[] Serialize();
    public static AuthRequestPayload Deserialize(byte[] data);
}

/// <summary>AUTH_RESPONSE: Agent → Client</summary>
public class AuthResponsePayload
{
    public bool Success { get; set; }
    public ushort ScreenWidth { get; set; }
    public ushort ScreenHeight { get; set; }
    public byte[] Serialize();
    public static AuthResponsePayload Deserialize(byte[] data);
}

// === 화면 ===

/// <summary>SCREEN_FULL: 전체 프레임 JPEG</summary>
public class ScreenFullPayload
{
    public ushort Width { get; set; }
    public ushort Height { get; set; }
    public byte[] JpegData { get; set; }
    public byte[] Serialize();
    public static ScreenFullPayload Deserialize(byte[] data);
}

// === 마우스 ===

/// <summary>MOUSE_MOVE: 정규화 좌표 (0.0~1.0)</summary>
public class MouseMovePayload
{
    public float NormalizedX { get; set; } // 0.0 ~ 1.0
    public float NormalizedY { get; set; }
    public byte[] Serialize();   // 8바이트 (float x2)
    public static MouseMovePayload Deserialize(byte[] data);
}

/// <summary>MOUSE_CLICK</summary>
public class MouseClickPayload
{
    public float NormalizedX { get; set; }
    public float NormalizedY { get; set; }
    public byte Button { get; set; }  // 0=좌, 1=우, 2=중
    public bool IsDown { get; set; }  // true=누름, false=뗌
    public byte[] Serialize();   // 10바이트
    public static MouseClickPayload Deserialize(byte[] data);
}

/// <summary>MOUSE_SCROLL</summary>
public class MouseScrollPayload
{
    public float NormalizedX { get; set; }
    public float NormalizedY { get; set; }
    public short Delta { get; set; }  // 양수=위, 음수=아래
    public byte[] Serialize();   // 10바이트
    public static MouseScrollPayload Deserialize(byte[] data);
}

// === 키보드 ===

/// <summary>KEY_EVENT</summary>
public class KeyEventPayload
{
    public ushort VirtualKeyCode { get; set; }
    public ushort ScanCode { get; set; }
    public bool IsDown { get; set; }        // true=KeyDown, false=KeyUp
    public bool IsExtended { get; set; }    // 확장 키 여부
    public byte[] Serialize();   // 6바이트
    public static KeyEventPayload Deserialize(byte[] data);
}

// === 하트비트 ===
// Heartbeat는 페이로드 없음 (빈 byte[])
```

### 3.6 TcpConnection.cs
```csharp
namespace RemoteDesktop.Common.Network;

/// <summary>
/// TCP 연결 래퍼. 패킷 송수신 + 하트비트 관리
/// </summary>
public class TcpConnection : IDisposable
{
    private TcpClient _client;
    private NetworkStream _stream;
    private CancellationTokenSource _cts;
    private System.Threading.Timer _heartbeatTimer;

    public TcpConnection(TcpClient client);

    public bool IsConnected { get; }

    // 패킷 전송
    public Task SendPacketAsync(PacketType type, byte[] payload);

    // 패킷 수신 (무한 루프, 콜백)
    public Task StartReceiveLoopAsync(
        Action<Packet> onPacketReceived,
        Action<Exception> onError);

    // 하트비트 시작 (5초 간격)
    public void StartHeartbeat();

    // 하트비트 타임아웃 감지 (15초 무응답 → 연결 종료)
    public event EventHandler ConnectionLost;

    public void Dispose();
}
```

