using Vortice.Direct3D;
using Vortice.Direct3D11;
using Vortice.DXGI;

namespace RemoteDesktop.Agent.Capture;

public interface IScreenCapturer : IDisposable
{
    int ScreenWidth { get; }
    int ScreenHeight { get; }

    /// <summary>현재 화면을 캡처하여 Bitmap 반환 (null = 변경 없음)</summary>
    Bitmap CaptureFrame();
}

public class DxgiScreenCapturer : IScreenCapturer
{
    private ID3D11Device _device;
    private ID3D11DeviceContext _context;
    private IDXGIOutputDuplication _duplication;
    private ID3D11Texture2D _stagingTexture;

    public int ScreenWidth { get; private set; }
    public int ScreenHeight { get; private set; }

    public DxgiScreenCapturer(int monitorIndex = 0)
    {
        // 1. IDXGIFactory1 생성
        // 2. 어댑터 열거 → monitorIndex 출력 선택
        // 3. D3D11CreateDevice (DriverType.Hardware)
        // 4. IDXGIOutput → IDXGIOutput1 → DuplicateOutput()
        // 5. 스테이징 텍스처 생성
        //    - Format: B8G8R8A8_UNorm
        //    - Usage: Staging
        //    - CpuAccessFlags: Read
    }

    public Bitmap CaptureFrame()
    {
        // 1. AcquireNextFrame(timeout: 100ms)
        //    → 타임아웃 시 null 반환 (화면 변경 없음)
        // 2. desktopResource → ID3D11Texture2D
        // 3. CopyResource(stagingTexture, desktopTexture)
        // 4. Map(stagingTexture, Read) → DataBox
        // 5. BGRA 픽셀 → Bitmap 생성 (PixelFormat.Format32bppArgb)
        //    - Marshal.Copy 행 단위 (RowPitch != Width*4 가능)
        // 6. ReleaseFrame()
        // 7. Bitmap 반환
    }

    /// <summary>DXGI 오류 시 재초기화 (모니터 변경/절전 복귀 등)</summary>
    private void Reinitialize();

    public void Dispose();
}
```

